    {"id": f"R-{i}", "vendor": name}
    for i, name in enumerate(["Acme Corp", "Beta LLC", "Gamma Inc",
        "Delta Ltd", "Epsilon SA", "Zeta GmbH", "Eta BV", "Theta AG"])
]

window = SlidingWindow(window_size=4, prefix_ratio=0.5)
chunks = window.chunks(records)
print(f"Total records: {len(records)}, Chunks: {len(chunks)}, Stride: {window.stride}")

all_results = []
for chunk_idx, (prefix, actionable) in enumerate(chunks):
